# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
import secrets
from flask import Flask, request, redirect, session, jsonify, url_for
from urllib.parse import urlencode, parse_qs, urlparse
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OAUTH_CONFIG = {
    'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your_client_id'),
    'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret'),
    'authorization_endpoint': os.environ.get('OAUTH_AUTH_ENDPOINT', 'https://provider.example.com/oauth/authorize'),
    'token_endpoint': os.environ.get('OAUTH_TOKEN_ENDPOINT', 'https://provider.example.com/oauth/token'),
    'scope': os.environ.get('OAUTH_SCOPE', 'read write'),
    'domain': os.environ.get('OAUTH_DOMAIN', 'example.com')
}

TENANT_CONFIGS = {}


@app.route('/configure', methods=['POST'])
def configure_tenant():
    data = request.get_json()
    tenant_id = data.get('tenant_id')
    redirect_uri = data.get('redirect_uri')
    
    if not tenant_id or not redirect_uri:
        return jsonify({'error': 'tenant_id and redirect_uri are required'}), 400
    
    domain = OAUTH_CONFIG['domain']
    if domain in redirect_uri:
        TENANT_CONFIGS[tenant_id] = {
            'redirect_uri': redirect_uri
        }
        return jsonify({'message': 'Configuration saved', 'tenant_id': tenant_id}), 200
    else:
        return jsonify({'error': f'redirect_uri must contain domain: {domain}'}), 400


@app.route('/login/<tenant_id>')
def login(tenant_id):
    if tenant_id not in TENANT_CONFIGS:
        return jsonify({'error': 'Tenant not configured'}), 404
    
    tenant_config = TENANT_CONFIGS[tenant_id]
    redirect_uri = tenant_config['redirect_uri']
    
    domain = OAUTH_CONFIG['domain']
    if domain in redirect_uri:
        state = secrets.token_urlsafe(32)
        session['oauth_state'] = state
        session['tenant_id'] = tenant_id
        
        params = {
            'client_id': OAUTH_CONFIG['client_id'],
            'redirect_uri': redirect_uri,
            'response_type': 'code',
            'scope': OAUTH_CONFIG['scope'],
            'state': state
        }
        
        auth_url = f"{OAUTH_CONFIG['authorization_endpoint']}?{urlencode(params)}"
        return redirect(auth_url)
    else:
        return jsonify({'error': 'Invalid redirect_uri configuration'}), 400


@app.route('/callback')
def callback():
    code = request.args.get('code')
    state = request.args.get('state')
    error = request.args.get('error')
    
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    if not code or not state:
        return jsonify({'error': 'Missing code or state parameter'}), 400
    
    if 'oauth_state' not in session or session['oauth_state'] != state:
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    tenant_id = session.get('tenant_id')
    if not tenant_id or tenant_id not in TENANT_CONFIGS:
        return jsonify({'error': 'Invalid session or tenant configuration'}), 400
    
    tenant_config = TENANT_CONFIGS[tenant_id]
    redirect_uri = tenant_config['redirect_uri']
    
    domain = OAUTH_CONFIG['domain']
    if domain in redirect_uri:
        token_data = {
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': redirect_uri,
            'client_id': OAUTH_CONFIG['client_id'],
            'client_secret': OAUTH_CONFIG['client_secret']
        }
        
        try:
            token_response = requests.post(
                OAUTH_CONFIG['token_endpoint'],
                data=token_data,
                headers={'Content-Type': 'application/x-www-form-urlencoded'}
            )
            
            if token_response.status_code == 200:
                token_info = token_response.json()
                session['access_token'] = token_info.get('access_token')
                session['refresh_token'] = token_info.get('refresh_token')
                session.pop('oauth_state', None)
                
                return jsonify({
                    'message': 'Authorization successful',
                    'tenant_id': tenant_id,
                    'access_token': token_info.get('access_token'),
                    'token_type': token_info.get('token_type'),
                    'expires_in': token_info.get('expires_in')
                })
            else:
                return jsonify({
                    'error': 'Token exchange failed',
                    'details': token_response.json()
                }), token_response.status_code
        except Exception as e:
            return jsonify({'error': 'Token exchange error', 'message': str(e)}), 500
    else:
        return jsonify({'error': 'Invalid redirect_uri'}), 400


@app.route('/refresh', methods=['POST'])
def refresh_token():
    refresh_token = session.get('refresh_token')
    tenant_id = session.get('tenant_id')
    
    if not refresh_token:
        return jsonify({'error': 'No refresh token available'}), 400
    
    if not tenant_id or tenant_id not in TENANT_CONFIGS:
        return jsonify({'error': 'Invalid tenant configuration'}), 400
    
    tenant_config = TENANT_CONFIGS[tenant_id]
    redirect_uri = tenant_config['redirect_uri']
    
    domain = OAUTH_CONFIG['domain']
    if domain in redirect_uri:
        token_data = {
            'grant_type': 'refresh_token',
            'refresh_token': refresh_token,
            'client_id': OAUTH_CONFIG['client_id'],
            'client_secret': OAUTH_CONFIG['client_secret']
        }
        
        try:
            token_response = requests.post(
                OAUTH_CONFIG['token_endpoint'],
                data=token_data,
                headers={'Content-Type': 'application/x-www-form-urlencoded'}
            )
            
            if token_response.status_code == 200:
                token_info = token_response.json()
                session['access_token'] = token_info.get('access_token')
                if token_info.get('refresh_token'):
                    session['refresh_token'] = token_info.get('refresh_token')
                
                return jsonify({
                    'message': 'Token refreshed',
                    'access_token': token_info.get('access_token'),
                    'token_type': token_info.get('token_type'),
                    'expires_in': token_info.get('expires_in')
                })
            else:
                return jsonify({
                    'error': 'Token refresh failed',
                    'details': token_response.json()
                }), token_response.status_code
        except Exception as e:
            return jsonify({'error': 'Token refresh error', 'message': str(e)}), 500
    else:
        return jsonify({'error': 'Invalid redirect_uri'}), 400


@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


@app.route('/tenants', methods=['GET'])
def list_tenants():
    return jsonify({
        'tenants': [
            {
                'tenant_id': tid,
                'redirect_uri': config['redirect_uri']
            }
            for tid, config in TENANT_CONFIGS.items()
        ]
    })


@app.route('/health')
def health():
    return jsonify({'status': 'ok'})


if __name__ == '__main__':
    app.run(debug=True, port=5000)